335:     pub args: I::GenericArgs,
336:     /// This field exists to prevent the creation of `ExistentialTraitRef` without
337:     /// calling [`ExistentialTraitRef::new_from_args`].
338:     _use_existential_trait_ref_new_instead: (),
339: }
