        let clauses: SmallVec<_> = data.into_iter().collect();
        let flags = FlagComputation::<DbInterner<'db>>::for_clauses(&clauses);
        let wrapper = InternedClausesWrapper(clauses, flags.flags, flags.outer_exclusive_binder);
